mapper.select:
SELECT vacuum_raw_metrics_id AS vacuumRawMetricsId, database_id AS databaseId, collected_at AS collectedAt, backend_pid AS backendPid, blocker_xmin_horizon AS blockerXminHorizon, blocker_pid AS blockerPid, blocker_lock_mode AS blockerLockMode, blocked_seconds AS blockedSeconds, blocker_transaction_state AS blockerTransactionState, is_blocked AS isBlocked, table_name AS tableName FROM vacuum_raw_metrics WHERE collected_at BETWEEN #{startTime} AND #{endTime}
AND database_id = #{databaseId}
AND blocker_xmin_horizon IS NOT NULL ORDER BY collected_at ASC

SELECT vacuum_raw_metrics_id AS vacuumRawMetricsId, database_id AS databaseId, collected_at AS collectedAt, blocker_xmin_horizon AS blockerXminHorizon, tuples_deleted AS tuplesDeleted, elapsed_seconds AS elapsedSeconds FROM vacuum_raw_metrics WHERE collected_at >= #{since}
AND database_id = #{databaseId}
ORDER BY collected_at DESC LIMIT 1000

SELECT vacuum_raw_metrics_id AS vacuumRawMetricsId, database_id AS databaseId, collected_at AS collectedAt, blocker_xmin_horizon AS blockerXminHorizon FROM vacuum_raw_metrics WHERE blocker_xmin_horizon IS NOT NULL
AND database_id = #{databaseId}
ORDER BY collected_at DESC LIMIT 100

SELECT vacuum_raw_metrics_id AS vacuumRawMetricsId, database_id AS databaseId, n_dead_tup AS nDeadTup, n_live_tup AS nLiveTup FROM vacuum_raw_metrics WHERE n_dead_tup > #{threshold}
AND database_id = #{databaseId}
ORDER BY n_dead_tup DESC LIMIT 100

SELECT vacuum_trend_metrics_id AS vacuumTrendMetricsId, database_id AS databaseId, table_name AS tableName, collected_at AS collectedAt, bloat_bytes AS bloatBytes, bloat_ratio AS bloatRatio FROM vacuum_trend_metrics WHERE collected_at >= #{startDate} AND bloat_bytes IS NOT NULL
AND database_id = #{databaseId}
ORDER BY collected_at ASC

WITH latest_per_table AS ( SELECT DISTINCT ON (database_id, table_name) database_id, table_name, bloat_ratio, collected_at FROM vacuum_trend_metrics WHERE collected_at >= #{since} AND bloat_ratio IS NOT NULL AND table_name IS NOT NULL
AND database_id = #{databaseId}
ORDER BY database_id, table_name, collected_at DESC ) SELECT CASE WHEN bloat_ratio < 0.05 THEN '0-5%' WHEN bloat_ratio < 0.10 THEN '5-10%' WHEN bloat_ratio < 0.15 THEN '10-15%' WHEN bloat_ratio < 0.20 THEN '15-20%' WHEN bloat_ratio < 0.30 THEN '20-30%' ELSE '30%+' END as range, COUNT(*) as count FROM latest_per_table GROUP BY range ORDER BY MIN(bloat_ratio)

WITH latest_per_table AS ( SELECT DISTINCT ON (database_id, table_name) database_id, table_name, bloat_bytes, collected_at FROM vacuum_trend_metrics WHERE collected_at >= #{since} AND bloat_bytes IS NOT NULL AND table_name IS NOT NULL
AND database_id = #{databaseId}
ORDER BY database_id, table_name, collected_at DESC ) SELECT COALESCE(SUM(bloat_bytes), 0) FROM latest_per_table

WITH latest_per_table AS ( SELECT DISTINCT ON (database_id, table_name) database_id, table_name, bloat_ratio, collected_at FROM vacuum_trend_metrics WHERE collected_at >= #{since} AND bloat_ratio IS NOT NULL AND table_name IS NOT NULL
AND database_id = #{databaseId}
ORDER BY database_id, table_name, collected_at DESC ) SELECT COUNT(*) FROM latest_per_table WHERE bloat_ratio >= 0.15

SELECT vacuum_trend_metrics_id AS vacuumTrendMetricsId, database_id AS databaseId, table_name AS tableName, collected_at AS collectedAt, bloat_bytes AS bloatBytes, bloat_ratio AS bloatRatio FROM vacuum_trend_metrics WHERE collected_at >= #{startDate} AND bloat_bytes IS NOT NULL
AND database_id = #{databaseId}
ORDER BY collected_at ASC

WITH latest_per_table AS ( SELECT DISTINCT ON (database_id, table_name) vacuum_trend_metrics_id, database_id, table_name, wraparound_progress_pct, collected_at FROM vacuum_trend_metrics WHERE wraparound_progress_pct IS NOT NULL AND wraparound_progress_pct > #{threshold} AND table_name IS NOT NULL
AND database_id = #{databaseId}
ORDER BY database_id, table_name, collected_at DESC ) SELECT vacuum_trend_metrics_id AS vacuumTrendMetricsId, database_id AS databaseId, table_name AS tableName, wraparound_progress_pct AS wraparoundProgressPct FROM latest_per_table ORDER BY wraparound_progress_pct DESC LIMIT 100

WITH latest AS ( SELECT database_id, table_name, MAX(collected_at) as max_collected_at FROM vacuum_trend_metrics WHERE table_name IS NOT NULL
AND database_id = #{databaseId}
GROUP BY database_id, table_name ) SELECT v.vacuum_trend_metrics_id AS vacuumTrendMetricsId, v.database_id AS databaseId, v.table_name AS tableName, v.collected_at AS collectedAt, v.bloat_bytes AS bloatBytes, v.bloat_ratio AS bloatRatio FROM vacuum_trend_metrics v INNER JOIN latest ON v.database_id = latest.database_id AND v.table_name = latest.table_name AND v.collected_at = latest.max_collected_at ORDER BY v.bloat_ratio DESC NULLS LAST LIMIT 100
